<?phpnamespace App\Controller;use App\Entity\SysAdminOperation;use App\Entity\TypeBien;use App\Form\TypeBienType;use App\Repository\TypeBienRepository;use DateTime;use DateTimeZone;use Exception;use Sensio\Bundle\FrameworkExtraBundle\Configuration\Security;use Symfony\Bundle\FrameworkBundle\Controller\AbstractController;use Symfony\Component\HttpFoundation\Request;use Symfony\Component\HttpFoundation\Response;use Symfony\Component\Routing\Annotation\Route;class TypeBienController extends AbstractController{    /**     * @Security("is_granted('ROLE_SUPER_ADMIN') and user.getIsActived() and user.getIsKohUser() and user.getIsConfirmed()")     * @Route("/super-admin/type-biens", name="type_bien_index", methods={"GET"})     * @param TypeBienRepository $typeBienRepository     * @return Response     */    public function index(TypeBienRepository $typeBienRepository): Response    {        return $this->render('type_bien/index.html.twig', [            'type_biens' => $typeBienRepository->findAll(),        ]);    }    /**     * @Security("is_granted('ROLE_SUPER_ADMIN') and user.getIsActived() and user.getIsKohUser() and user.getIsConfirmed() and user.getIsAdmin()")     * @Route("/super-admin/type-biens/new", name="type_bien_new", methods={"GET","POST"})     * @param Request $request     * @return Response     * @throws Exception     */    public function new(Request $request): Response    {        $typeBien = new TypeBien();        $form = $this->createForm(TypeBienType::class, $typeBien);        $form->handleRequest($request);        if ($form->isSubmitted() && $form->isValid()) {            $entityManager = $this->getDoctrine()->getManager();            $entityManager->persist($typeBien);            $entityManager->flush();            $this->addFlash('success', 'Le type de bien a été enregistré');            $sysOp = new SysAdminOperation();            $sysOp->setCreatedAt(new DateTime('now', new DateTimeZone('GMT')))                ->setKohUtilisateur($this->getUser())                ->setDescription('Enregistrement type bien')                ->setUserAffected($typeBien->getName());            $entityManager->persist($sysOp);            $entityManager->flush();            return $this->redirectToRoute('type_bien_index');        }        return $this->render('type_bien/new.html.twig', [            'type_bien' => $typeBien,            'form' => $form->createView(),        ]);    }    /**     * @Route("/super-admin/type-biens/{id}", name="type_bien_show", methods={"GET"})     * @param TypeBien $typeBien     * @return Response     */    public function show(TypeBien $typeBien): Response    {        return $this->render('type_bien/show.html.twig', [            'type_bien' => $typeBien,        ]);    }    /**     * @Security("is_granted('ROLE_SUPER_ADMIN') and user.getIsActived() and user.getIsKohUser() and user.getIsConfirmed() and user.getIsAdmin()")     * @Route("/super-admin/type-biens/{id}/edit", name="type_bien_edit", methods={"GET","POST"})     * @param Request $request     * @param TypeBien $typeBien     * @return Response     * @throws Exception     */    public function edit(Request $request, TypeBien $typeBien): Response    {        $form = $this->createForm(TypeBienType::class, $typeBien);        $form->handleRequest($request);        if ($form->isSubmitted() && $form->isValid()) {            $this->getDoctrine()->getManager()->flush();            $this->addFlash('success', 'Le type de bien a été modifié');            $sysOp = new SysAdminOperation();            $sysOp->setCreatedAt(new DateTime('now', new DateTimeZone('GMT')))                ->setKohUtilisateur($this->getUser())                ->setDescription('Modification type bien')                ->setUserAffected($typeBien->getName());            $this->getDoctrine()->getManager()->persist($sysOp);            $this->getDoctrine()->getManager()->flush();            return $this->redirectToRoute('type_bien_index');        }        return $this->render('type_bien/edit.html.twig', [            'type_bien' => $typeBien,            'form' => $form->createView(),        ]);    }    /**     * @Security("is_granted('ROLE_SUPER_ADMIN') and user.getIsActived() and user.getIsKohUser() and user.getIsConfirmed() and user.getIsAdmin()")     * @Route("/super-admin/type-biens/{id}", name="type_bien_delete", methods={"DELETE"})     * @param Request $request     * @param TypeBien $typeBien     * @return Response     */    public function delete(Request $request, TypeBien $typeBien): Response    {        if ($this->isCsrfTokenValid('delete' . $typeBien->getId(), $request->request->get('_token'))) {            $entityManager = $this->getDoctrine()->getManager();            $entityManager->remove($typeBien);            $entityManager->flush();            $this->addFlash('success', 'Le type de bien a été supprimé');            $sysOp = new SysAdminOperation();            $sysOp->setCreatedAt(new DateTime('now', new DateTimeZone('GMT')))                ->setKohUtilisateur($this->getUser())                ->setDescription('Suppression type bien')                ->setUserAffected($typeBien->getName());            $this->getDoctrine()->getManager()->persist($sysOp);            $this->getDoctrine()->getManager()->flush();        }        return $this->redirectToRoute('type_bien_index');    }}